-- Phase A1: one row per completed fixture, auto-generated by the learning engine.
-- Source of truth for Decision Review (Tab 1) and Engine Learning (Tab 2)
-- on the Performance page. Learning signals are derived from this table at read time.

CREATE TABLE IF NOT EXISTS match_reviews (
  fixture_id       text PRIMARY KEY,
  engine_h         smallint,          -- pool recommendation home goals (null if no rec stored)
  engine_a         smallint,
  my_h             smallint NOT NULL,
  my_a             smallint NOT NULL,
  actual_h         smallint NOT NULL,
  actual_a         smallint NOT NULL,
  my_pts           smallint NOT NULL, -- pool points earned (4/2/1/0)
  engine_pts       smallint,          -- points the rec would have earned (null if no rec)
  overridden       boolean NOT NULL DEFAULT false,
  override_reason  text,
  evidence         jsonb,             -- string[] of context bullets
  impact_verdict   text NOT NULL,     -- 'Override succeeded' | 'Override failed' | 'Both matched' | 'Both missed' | 'Accepted rec'
  lesson           text NOT NULL,     -- one-sentence learning
  blind_spot       text,              -- BlindSpotCategory if engine failed
  engine_version   text NOT NULL DEFAULT '1.0',
  created_at       timestamptz NOT NULL DEFAULT now()
);
